  ('disabled-6f0ba476-moex-00403', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-f6c431ec', 'sub-disabled-6f0ba476-05', NULL, 'single_choice', '將受僱者所繳納之勞工保險保費視為薪工稅（payrolltax），在勞動市場完全 競爭下，下列敘述何者錯誤？', '["勞工保險保費為對特定要素報酬所課徵之從價稅", "雇主與勞工之法定與經濟歸宿並不相等", "雇主與勞工之經濟歸宿大小，與勞動供需彈性有關", "雇主與勞工之經濟歸宿大小，與雇主與勞工保險保費分擔比例有關"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "4af391f11fdd", "answer_pdf_sha1": "23b6871a820f", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
